// AnnotationCanvas.js (Updated)
import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Transformer,
} from 'react-konva';
import './AnnotationCanvas.css';

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool,
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape,
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);

  // Master group offset (image panning)
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shapes
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  // Shape selection for Transformer
  const [selectedAnnotationIndex, setSelectedAnnotationIndex] = useState(null);
  const transformerRef = useRef(null);
  const shapeRefs = useRef([]);

  // -------------------------- Window / container sizing --------------------------
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      setDims({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight,
      });
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // -------------------------- Load image --------------------------
  useEffect(() => {
    if (!fileUrl) return;
    const img = new window.Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // -------------------------- Helper: flatten {x, y} => [x, y, x, y, ...] --------------------------
  function flattenPoints(pts) {
    return pts.flatMap((p) => [p.x, p.y]);
  }

  // -------------------------- For coordinate conversions --------------------------
  function getGroupPos(evt) {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  }

  // -------------------------- Check if shape is outside image --------------------------
  function shapeBoundingBox(ann) {
    if (ann.type === 'bbox') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x + ann.width,
        y2: ann.y + ann.height,
      };
    } else if (ann.type === 'ellipse') {
      return {
        x1: ann.x - ann.radiusX,
        y1: ann.y - ann.radiusY,
        x2: ann.x + ann.radiusX,
        y2: ann.y + ann.radiusY,
      };
    } else if (ann.type === 'polygon' || ann.type === 'polyline') {
      let minX = Infinity,
        minY = Infinity,
        maxX = -Infinity,
        maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    } else if (ann.type === 'point') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x,
        y2: ann.y,
      };
    }
    return null;
  }

  function isOutsideImage(ann) {
    if (!konvaImg) return false;
    const { x1, y1, x2, y2 } = shapeBoundingBox(ann);
    if (x2 < 0 || x1 > konvaImg.width || y2 < 0 || y1 > konvaImg.height) {
      return true;
    }
    return false;
  }

  // -------------------------- Creating BBox --------------------------
  function startBox(pos) {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  }
  function updateBox(pos) {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  }
  function finalizeBox() {
    if (!newBox) return;
    const newAnn = { type: 'bbox', ...newBox, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  }

  // -------------------------- Creating Polygon --------------------------
  function addPolygonPoint(pos) {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  }
  function finalizePolygon() {
    if (tempPoints.length >= 3) {
      const newAnn = { type: 'polygon', points: tempPoints, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  }

  // -------------------------- Creating Polyline --------------------------
  function addPolylinePoint(pos) {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  }
  function finalizePolyline() {
    if (tempPolyline.length >= 2) {
      const newAnn = { type: 'polyline', points: tempPolyline, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  }

  // -------------------------- Creating Point --------------------------
  function addPoint(pos) {
    const newAnn = { type: 'point', x: pos.x, y: pos.y, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    onFinishShape && onFinishShape();
  }

  // -------------------------- Creating Ellipse --------------------------
  function startEllipse(pos) {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: '',
    });
  }
  function updateEllipse(pos) {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  }
  function finalizeEllipse() {
    if (!newEllipse) return;
    if (!isOutsideImage(newEllipse)) {
      onAnnotationsChange([...annotations, { ...newEllipse }]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  }

  // -------------------------- Cancel shape creation on ESC --------------------------
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // -------------------------- Wheel Zoom --------------------------
  function handleWheel(evt) {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  }

  // -------------------------- Mouse events for shape creation --------------------------
  function handleMouseDown(evt) {
    if (selectedTool === 'move') {
      // Let user pan the image if they drag on empty space
      return;
    }
    const pos = getGroupPos(evt);
    if (!pos) return;

    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    } else if (selectedTool === 'polyline') {
      addPolylinePoint(pos);
    } else if (selectedTool === 'point') {
      addPoint(pos);
    } else if (selectedTool === 'ellipse') {
      startEllipse(pos);
    }
  }

  function handleMouseMove(evt) {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  }

  function handleMouseUp() {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  }

  function handleDblClick() {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    }
  }

  // -------------------------- Drag-end handlers for existing shapes --------------------------
  const handleBBoxDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handleEllipseDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handlePointDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handlePolygonDragEnd = (index, e) => {
    e.cancelBubble = true;
    const shape = e.target;
    const { x, y } = shape.position();

    // Shift all polygon points by the drag offset
    const updated = [...annotations];
    const newPoints = updated[index].points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));

    updated[index] = { ...updated[index], points: newPoints };
    shape.position({ x: 0, y: 0 });

    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handlePolylineDragEnd = (index, e) => {
    e.cancelBubble = true;
    const shape = e.target;
    const { x, y } = shape.position();

    // Shift all polyline points by the drag offset
    const updated = [...annotations];
    const newPoints = updated[index].points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));

    updated[index] = { ...updated[index], points: newPoints };
    shape.position({ x: 0, y: 0 });

    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  // -------------------------- Transformer logic --------------------------
  useEffect(() => {
    const tr = transformerRef.current;
    if (!tr) return;

    if (selectedAnnotationIndex == null) {
      tr.nodes([]);
      return;
    }

    const node = shapeRefs.current[selectedAnnotationIndex];
    if (node) {
      tr.nodes([node]);
      tr.getLayer().batchDraw();
    } else {
      tr.nodes([]);
    }
  }, [selectedAnnotationIndex, annotations, onAnnotationsChange]);

  const handleTransformEnd = () => {
    if (selectedAnnotationIndex == null) return;
    const shapeNode = shapeRefs.current[selectedAnnotationIndex];
    if (!shapeNode) return;

    const ann = annotations[selectedAnnotationIndex];
    const scaleX = shapeNode.scaleX();
    const scaleY = shapeNode.scaleY();
    const offsetX = shapeNode.x();
    const offsetY = shapeNode.y();

    let updatedAnn = { ...ann };

    switch (ann.type) {
      case 'bbox': {
        const newWidth = shapeNode.width() * scaleX;
        const newHeight = shapeNode.height() * scaleY;
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        updatedAnn.width = newWidth;
        updatedAnn.height = newHeight;
        break;
      }
      case 'ellipse': {
        const newRadiusX = (shapeNode.width() / 2) * scaleX;
        const newRadiusY = (shapeNode.height() / 2) * scaleY;
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        updatedAnn.radiusX = newRadiusX;
        updatedAnn.radiusY = newRadiusY;
        break;
      }
      case 'point': {
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        break;
      }
      case 'polygon':
      case 'polyline': {
        // Scale all points + offset
        const newPoints = ann.points.map((pt) => ({
          x: pt.x * scaleX + offsetX,
          y: pt.y * scaleY + offsetY,
        }));
        updatedAnn.points = newPoints;
        break;
      }
      default:
        break;
    }

    shapeNode.scaleX(1);
    shapeNode.scaleY(1);
    shapeNode.x(0);
    shapeNode.y(0);

    const updatedAll = [...annotations];
    updatedAll[selectedAnnotationIndex] = updatedAnn;

    if (isOutsideImage(updatedAnn)) {
      updatedAll.splice(selectedAnnotationIndex, 1);
    }
    onAnnotationsChange(updatedAll);
  };

  // -------------------------- Render --------------------------
  const fillColor = activeLabelColor + '55';

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {/* The background image */}
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Existing shapes */}
            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                return (
                  <Rect
                    key={i}
                    ref={(node) => (shapeRefs.current[i] = node)}
                    x={ann.x}
                    y={ann.y}
                    width={ann.width}
                    height={ann.height}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    draggable
                    onMouseDown={(e) => e.cancelBubble = true}
                    onDragStart={(e) => e.cancelBubble = true}
                    onDragMove={(e) => e.cancelBubble = true}
                    onDragEnd={(e) => handleBBoxDragEnd(i, e)}
                    onClick={(e) => {
                      if (selectedTool === 'move') {
                        e.cancelBubble = true;
                        setSelectedAnnotationIndex(i);
                      }
                    }}
                  />
                );
              } else if (ann.type === 'ellipse') {
                return (
                  <Ellipse
                    key={i}
                    ref={(node) => (shapeRefs.current[i] = node)}
                    x={ann.x}
                    y={ann.y}
                    radiusX={ann.radiusX}
                    radiusY={ann.radiusY}
                    rotation={ann.rotation || 0}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    draggable
                    onMouseDown={(e) => e.cancelBubble = true}
                    onDragStart={(e) => e.cancelBubble = true}
                    onDragMove={(e) => e.cancelBubble = true}
                    onDragEnd={(e) => handleEllipseDragEnd(i, e)}
                    onClick={(e) => {
                      if (selectedTool === 'move') {
                        e.cancelBubble = true;
                        setSelectedAnnotationIndex(i);
                      }
                    }}
                  />
                );
              } else if (ann.type === 'point') {
                return (
                  <Circle
                    key={i}
                    ref={(node) => (shapeRefs.current[i] = node)}
                    x={ann.x}
                    y={ann.y}
                    radius={6 / scale}
                    fill={activeLabelColor}
                    draggable
                    onMouseDown={(e) => e.cancelBubble = true}
                    onDragStart={(e) => e.cancelBubble = true}
                    onDragMove={(e) => e.cancelBubble = true}
                    onDragEnd={(e) => handlePointDragEnd(i, e)}
                    onClick={(e) => {
                      if (selectedTool === 'move') {
                        e.cancelBubble = true;
                        setSelectedAnnotationIndex(i);
                      }
                    }}
                  />
                );
              } else if (ann.type === 'polygon') {
                return (
                  <Line
                    key={i}
                    ref={(node) => (shapeRefs.current[i] = node)}
                    points={flattenPoints(ann.points)}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                    draggable
                    onMouseDown={(e) => e.cancelBubble = true}
                    onDragStart={(e) => e.cancelBubble = true}
                    onDragMove={(e) => e.cancelBubble = true}
                    onDragEnd={(e) => handlePolygonDragEnd(i, e)}
                    onClick={(e) => {
                      if (selectedTool === 'move') {
                        e.cancelBubble = true;
                        setSelectedAnnotationIndex(i);
                      }
                    }}
                  />
                );
              } else if (ann.type === 'polyline') {
                return (
                  <Line
                    key={i}
                    ref={(node) => (shapeRefs.current[i] = node)}
                    points={flattenPoints(ann.points)}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed={false}
                    draggable
                    onMouseDown={(e) => e.cancelBubble = true}
                    onDragStart={(e) => e.cancelBubble = true}
                    onDragMove={(e) => e.cancelBubble = true}
                    onDragEnd={(e) => handlePolylineDragEnd(i, e)}
                    onClick={(e) => {
                      if (selectedTool === 'move') {
                        e.cancelBubble = true;
                        setSelectedAnnotationIndex(i);
                      }
                    }}
                  />
                );
              }
              return null;
            })}

            {/* In-progress BBox */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Polygon */}
            {drawingPolygon && tempPoints.length > 1 && selectedTool === 'polygon' && (
              <Line
                points={flattenPoints([...tempPoints, tempPoints[0]])}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed
              />
            )}

            {/* In-progress Polyline */}
            {drawingPolyline && tempPolyline.length > 1 && selectedTool === 'polyline' && (
              <Line
                points={flattenPoints(tempPolyline)}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed={false}
              />
            )}

            {/* In-progress Ellipse */}
            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={0}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}
          </Group>

          {/* Single Transformer for resizing the selected shape */}
          <Transformer
            ref={transformerRef}
            rotateEnabled={false}
            anchorSize={8}
            borderDash={[6, 2]}
            onTransformEnd={handleTransformEnd}
            onDragEnd={handleTransformEnd}
          />
        </Layer>
      </Stage>
    </div>
  );
}
